+        .checked_sub(SYMBOL_SEGMENT_HEADER_BYTES)
+        .ok_or_else(|| FrankenError::DatabaseCorrupt {
+            detail: format!(
+                "record offset {absolute_offset} precedes segment header of {SYMBOL_SEGMENT_HEADER_BYTES} bytes"
+            ),
+        })?;
+
+    let offset = SymbolLogOffset {
+        segment_id,
